namespace sv_29ea6d9897914a02ae721b4fd1df1ad6.Services;

public class WizardState
{
    public const int TotalSteps = 4;

    // Step 1 data
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 data
    public List<JobExperience> Experience { get; set; } = [];

    // Step 3 data
    public List<Reference> References { get; set; } = [];

    // Progress tracking
    public HashSet<int> CompletedSteps { get; } = [];
    public int CurrentStep { get; private set; } = 1;

    public event Action? OnChange;

    public void SetCurrentStep(int step)
    {
        CurrentStep = step;
        NotifyChanged();
    }

    public void CompleteStep(int step)
    {
        CompletedSteps.Add(step);
        NotifyChanged();
    }

    private void NotifyChanged() => OnChange?.Invoke();
}

public class JobExperience
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class Reference
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

@rendermode InteractiveServer
@inject sv_29ea6d9897914a02ae721b4fd1df1ad6.Services.WizardState Wizard
@implements IDisposable

@if (Wizard.CurrentStep >= 1 && Wizard.CurrentStep <= WizardState.TotalSteps)
{
    <div class="wizard-progress">
        <span class="wizard-label">Step @Wizard.CurrentStep of @WizardState.TotalSteps</span>
        <div class="wizard-steps">
            @for (int i = 1; i <= WizardState.TotalSteps; i++)
            {
                var step = i;
                var css = step == Wizard.CurrentStep ? "step active"
                    : Wizard.CompletedSteps.Contains(step) ? "step completed"
                    : "step";
                <div class="@css">@step</div>
            }
        </div>
    </div>
}

@code {
    protected override void OnInitialized()
    {
        Wizard.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Wizard.OnChange -= StateHasChanged;
    }
}

.wizard-progress {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.5rem 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
}

.wizard-label {
    font-weight: 600;
    white-space: nowrap;
}

.wizard-steps {
    display: flex;
    gap: 0.5rem;
}

.step {
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.875rem;
    font-weight: 600;
    background: #dee2e6;
    color: #495057;
}

.step.active {
    background: #0d6efd;
    color: white;
}

.step.completed {
    background: #198754;
    color: white;
}

