@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_29ea6d9897914a02ae721b4fd1df1ad6.Services.WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input class="form-control" type="email" @bind="Wizard.Email" />
</div>

<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(1);
    }

    private void Next()
    {
        Wizard.CompleteStep(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_29ea6d9897914a02ae721b4fd1df1ad6.Services.WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Experience</PageTitle>

<h3>Step 2: Work Experience</h3>

@for (int i = 0; i < Wizard.Experience.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Wizard.Experience[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="Wizard.Experience[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="Wizard.Experience[index].Years" />
        </div>
        <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(index)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="Add">+ Add Experience</button>

<div>
    <button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(2);
    }

    private void Add() => Wizard.Experience.Add(new());
    private void Remove(int index) => Wizard.Experience.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.CompleteStep(2);
        Nav.NavigateTo("/apply/references");
    }
}

